#include <ctime>
#include <iostream>

int main() {
    std::time_t now = std::time(nullptr);

    // localtime تحول time_t إلى بنية tm بالتوقيت المحلي
    // تحذر: تُرجع مؤشرًا لذاكرة ثابتة — لا تحتفظ به بعد استدعاء آخر
    std::tm* local = std::localtime(&now);

    // الانزياحات من إرث C: السنة منذ 1900، الشهر يبدأ من صفر
    std::cout << "السنة: " << (local->tm_year + 1900) << '\n';
    std::cout << "الشهر: " << (local->tm_mon + 1) << '\n';
    std::cout << "اليوم: " << local->tm_mday << '\n';  // يبدأ من 1 — بدون انزياح
    std::cout << "الساعة: " << local->tm_hour << '\n';
    std::cout << "الدقيقة: " << local->tm_min << '\n';
    std::cout << "الثانية: " << local->tm_sec << '\n';
    std::cout << "يوم الأسبوع: " << local->tm_wday << " (0=أحد)" << '\n';
    std::cout << "يوم السنة: " << local->tm_yday << " (0=يناير 1)" << '\n';

    return 0;
}

#include <ctime>
#include <iostream>

int main() {
    std::time_t now = std::time(nullptr);
    std::tm* local = std::localtime(&now);
    char buf[128];

    // صيغة ISO 8601: الأنسب للملفات والسجلات والفرز
    std::strftime(buf, sizeof(buf), "%Y-%m-%d %H:%M:%S", local);
    std::cout << "ISO: " << buf << '\n';

    // صيغة ودية: مناسبة لعرض المستخدم
    std::strftime(buf, sizeof(buf), "%A %d %B %Y - %I:%M %p", local);
    std::cout << "ودية: " << buf << '\n';

    // صيغة اسم ملف آمن: لا تحتوي مسافات أو أحرف خاصة
    std::strftime(buf, sizeof(buf), "log_%Y%m%d_%H%M%S.txt", local);
    std::cout << "ملف: " << buf << '\n';

    // التاريخ فقط بدون وقت
    std::strftime(buf, sizeof(buf), "%Y/%m/%d", local);
    std::cout << "تاريخ: " << buf << '\n';

    // الوقت فقط بدون تاريخ
    std::strftime(buf, sizeof(buf), "%H:%M:%S", local);
    std::cout << "وقت: " << buf << '\n';

    return 0;
}

#include <ctime>
#include <iostream>

int main() {
    std::time_t now = std::time(nullptr);

    // localtime: توقيت النظام المحلي (مثل الرياض +3)
    std::tm* local = std::localtime(&now);

    // gmtime: توقيت UTC — دائمًا نفسه بغض النظر عن الموقع
    std::tm* utc = std::gmtime(&now);

    // تحذير: لا تستخدم local بعد gmtime لأنهما يشيران لنفس الذاكرة!
    // لذلك طبعنا local قبل gmtime هنا

    char local_buf[80], utc_buf[80];
    std::strftime(local_buf, sizeof(local_buf), "%Y-%m-%d %H:%M:%S", local);
    std::strftime(utc_buf, sizeof(utc_buf), "%Y-%m-%d %H:%M:%S", utc);

    std::cout << "محلي: " << local_buf << '\n';
    std::cout << "UTC:   " << utc_buf << '\n';

    return 0;
}

#include <ctime>
#include <iostream>

int main() {
    // لحظتان زمنيتان: الآن وساعة لاحقًا
    std::time_t now = std::time(nullptr);
    std::time_t later = now + 3600; // +3600 ثانية = ساعة واحدة

    // difftime تُرجع الفرق بالثواني كعدد عشري
    double diff = std::difftime(later, now);

    std::cout << "الفرق: " << diff << " ثانية" << '\n';
    std::cout << "الفرق: " << (diff / 60) << " دقيقة" << '\n';
    std::cout << "الفرق: " << (diff / 3600) << " ساعة" << '\n';

    // استخدام عملي: حساب عمر ملف بالأيام
    std::time_t file_time = now - (7 * 24 * 3600); // ملف من أسبوع
    double age_days = std::difftime(now, file_time) / (24 * 3600);
    std::cout << "عمر الملف: " << age_days << " يوم" << '\n';

    return 0;
}

#include <ctime>
#include <iostream>

int main() {
    std::tm target{};

    // بناء تاريخ يدويًا — انتبه للانزياحات!
    target.tm_year = 2025 - 1900;  // السنة منذ 1900
    target.tm_mon  = 2;             // مارس = 2 (يناير = 0)
    target.tm_mday = 1;             // اليوم يبدأ من 1 طبيعيًا
    target.tm_hour = 10;
    target.tm_min  = 30;
    target.tm_sec  = 0;
    target.tm_isdst = -1;           // دع النظام يقرر التوقيت الصيفي

    // mktime تحول tm إلى time_t وتُصلح القيم غير الصالحة تلقائيًا
    std::time_t result = std::mktime(&target);

    if (result != (std::time_t)-1) {
        std::cout << "تم التحويل بنجاح" << '\n';

        // الآن يمكننا استخدام strftime أو difftime مع هذا التاريخ
        char buf[80];
        std::strftime(buf, sizeof(buf), "%Y-%m-%d %H:%M:%S", &target);
        std::cout << "التاريخ: " << buf << '\n';
    }

    return 0;
}

#include <ctime>
#include <iostream>

int main() {
    std::tm date{};
    date.tm_year = 2025 - 1900;
    date.tm_mon  = 0;   // يناير
    date.tm_mday = 32;   // ❌ يناير ليس فيه 32 يوم!
    date.tm_hour = 10;
    date.tm_isdst = -1;

    // mktime ستصحح هذا تلقائيًا إلى 1 فبراير
    std::mktime(&date);

    char buf[80];
    std::strftime(buf, sizeof(buf), "%Y-%m-%d", &date);
    std::cout << "بعد التصحيح: " << buf << '\n';
    // الناتج: 2025-02-01

    // استخدام عملي: إضافة أيام لتاريخ
    std::tm future{};
    future.tm_year = 2025 - 1900;
    future.tm_mon  = 2;  // مارس
    future.tm_mday = 25 + 10;  // أضف 10 أيام
    future.tm_isdst = -1;

    std::mktime(&future);
    std::strftime(buf, sizeof(buf), "%Y-%m-%d", &future);
    std::cout << "بعد 10 أيام: " << buf << '\n';
    // الناتج: 2025-04-04 (انتقل تلقائيًا لأبريل)

    return 0;
}

#include <chrono>
#include <ctime>
#include <iostream>

int main() {
    // chrono تعطيك time_point بدقة عالية
    auto now_chrono = std::chrono::system_clock::now();

    // تحويل time_point إلى time_t للتعامل مع دوال <ctime>
    std::time_t now_time = std::chrono::system_clock::to_time_t(now_chrono);

    // الآن يمكنك استخدام أي دالة <ctime> عادية
    std::tm* local = std::localtime(&now_time);
    char buf[80];
    std::strftime(buf, sizeof(buf), "%Y-%m-%d %H:%M:%S", local);
    std::cout << "عبر chrono + ctime: " << buf << '\n';

    // العكس: تحويل time_t إلى time_point
    std::time_t some_time = std::time(nullptr);
    auto some_point = std::chrono::system_clock::from_time_t(some_time);

    return 0;
}

#include <ctime>
#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> data(100000);
    for (auto& v : data) v = rand();

    // clock تقيس وقت المعالج (CPU time) لا وقت الجدار
    std::clock_t start = std::clock();
    std::sort(data.begin(), data.end());
    std::clock_t end = std::clock();

    // CLOCKS_PER_SEC يُحوّل من ticks إلى ثوانٍ
    double seconds = double(end - start) / CLOCKS_PER_SEC;
    std::cout << "الترتيب استهلك: " << seconds << " ثانية CPU" << '\n';

    return 0;
}

#include <chrono>
#include <iostream>
#include <vector>
#include <algorithm>

int main() {
    std::vector<int> data(100000);
    for (auto& v : data) v = rand();

    // steady_clock لا تُعدَّل للخلف أبدًا — الأنسب للقياس
    auto start = std::chrono::steady_clock::now();
    std::sort(data.begin(), data.end());
    auto end = std::chrono::steady_clock::now();

    // الطرح بين نقطتين زمنيتين يُنتج duration
    auto duration_ns = end - start;

    // تحويل للوحدة المناسبة للعرض
    auto duration_us = std::chrono::duration_cast<std::chrono::microseconds>(duration_ns);
    auto duration_ms = std::chrono::duration_cast<std::chrono::milliseconds>(duration_ns);

    std::cout << "بالنانوثانية: " << duration_ns.count() << " ns" << '\n';
    std::cout << "بالميكروثانية: " << duration_us.count() << " us" << '\n';
    std::cout << "بالملي ثانية: " << duration_ms.count() << " ms" << '\n';

    return 0;
}

#include <ctime>
#include <chrono>
#include <iostream>
#include <thread>

int main() {
    // === المقارنة: clock تقيس CPU time فقط ===
    std::clock_t cpu_start = std::clock();

    // sleep لا يستهلك CPU — clock لن تحسبه
    std::this_thread::sleep_for(std::chrono::milliseconds(100));

    std::clock_t cpu_end = std::clock();
    double cpu_time = double(cpu_end - cpu_start) / CLOCKS_PER_SEC;
    std::cout << "clock (CPU): " << cpu_time << " ثانية" << '\n';
    // ستكون قريبة من صفر رغم الانتظار 100ms!

    // === المقارنة: steady_clock تقيس وقت الجدار الفعلي ===
    auto wall_start = std::chrono::steady_clock::now();
    std::this_thread::sleep_for(std::chrono::milliseconds(100));
    auto wall_end = std::chrono::steady_clock::now();

    auto wall_ms = std::chrono::duration_cast<std::chrono::milliseconds>(wall_end - wall_start);
    std::cout << "steady_clock (wall): " << wall_ms.count() << " ms" << '\n';
    // ستكون ~100ms — الوقت الفعلي الذي مر

    return 0;
}

