#include <chrono>
#include <iostream>

int main() {
    // ❌ system_clock قد تقفز للخلف إذا غيّر المستخدم ساعة النظام
    // أو حدثت مزامنة NTP أثناء القياس
    // auto start = std::chrono::system_clock::now();
    // ... عملية ...
    // auto end = std::chrono::system_clock::now();
    // الناتج قد يكون سلبيًا! أو أكبر بكثير من الواقع

    // ✅ steady_clock مضمونة أنها لا تُرجع للخلف أبدًا
    auto start = std::chrono::steady_clock::now();
    volatile int dummy = 0;
    for (int i = 0; i < 1000000; ++i) ++dummy;
    auto end = std::chrono::steady_clock::now();

    auto us = std::chrono::duration_cast<std::chrono::microseconds>(end - start);
    std::cout << "المدة: " << us.count() << " ميكروثانية" << '\n';

    return 0;
}

#include <ctime>
#include <iostream>

void log_event(const char* message) {
    std::time_t now = std::time(nullptr);

    // gmtime لأن السجل يجب أن يكون موحدًا عالميًا
    // خادم في الرياض وخادم في نيويورك يُنتجان نفس الختم لنفس الحدث
    std::tm* utc = std::gmtime(&now);

    char buf[128];
    std::strftime(buf, sizeof(buf), "[%Y-%m-%d %H:%M:%S UTC] %s", utc);
    std::cout << buf << '\n';
}

