#include <ctime>
#include <chrono>
#include <iostream>

int main() {
    std::time_t now = std::time(nullptr);
    std::tm* local = std::localtime(&now);
    char buf[128];

    // 1. طباعة سريعة: ctime
    std::cout << "سريع: " << std::ctime(&now);

    // 2. صيغة مخصصة: strftime
    std::strftime(buf, sizeof(buf), "%Y-%m-%d", local);
    std::cout << "مخصص: " << buf << '\n';

    // 3. فرق بين تاريخين: difftime
    double diff = std::difftime(now + 3600, now);
    std::cout << "فرق: " << diff << " ثانية" << '\n';

    // 4. بناء تاريخ من أرقام: mktime
    std::tm target{};
    target.tm_year = 2025 - 1900;
    target.tm_mon = 11; // ديسمبر
    target.tm_mday = 31;
    target.tm_isdst = -1;
    std::time_t target_t = std::mktime(&target);

    // 5. قياس أداء: steady_clock (لا تستخدم clock إلا لـ CPU time)
    auto t1 = std::chrono::steady_clock::now();
    volatile int x = 0;
    for (int i = 0; i < 1000; ++i) ++x;
    auto t2 = std::chrono::steady_clock::now();
    auto ms = std::chrono::duration_cast<std::chrono::microseconds>(t2 - t1);
    std::cout << "أداء: " << ms.count() << " us" << '\n';

    // 6. تاريخ/وقت حقيقي مع chrono: system_clock
    auto chrono_now = std::chrono::system_clock::now();
    auto tt = std::chrono::system_clock::to_time_t(chrono_now);
    std::cout << "chrono: " << std::ctime(&tt);

    return 0;
}
